    public void sendSimpleEmail(String to, String subject, String text) {
        try {
            SimpleMailMessage msg = new SimpleMailMessage();
            msg.setFrom(FROM);
            msg.setTo(to);
            msg.setSubject(subject);
            msg.setText(text);
            mailSender.send(msg);
            log.info("✉️ Simple email sent to: {}", to);
        } catch (Exception e) {
            log.error("❌ Failed to send simple email to {}: {}", to, e.getMessage());
        }
    }

    // ─────────────────────────────────────────────────────────────────
    //  1. BOOKING CONFIRMATION (with QR attachment)
    // ─────────────────────────────────────────────────────────────────
    @Async
    public void sendBookingConfirmation(Booking booking) {
        try {
            MimeMessage message = mailSender.createMimeMessage();
            MimeMessageHelper helper = new MimeMessageHelper(message, true, "UTF-8");
            helper.setFrom(FROM);
            helper.setTo(booking.getUser().getEmail());
            helper.setSubject("\ud83c\udf9f️ Booking Confirmed — " + booking.getEvent().getEventName());

            // Embed QR as inline CID image (works in all email clients including Gmail)
            if (booking.getQrCodeData() != null && booking.getQrCodeData().contains("base64,")) {
                String base64Data = booking.getQrCodeData().split(",")[1];
                byte[] qrBytes = Base64.getDecoder().decode(base64Data);
                String cid = "qrcode_" + booking.getBookingReference();
                helper.setText(buildBookingHtml(booking, cid), true);
                helper.addInline(cid,
                    new org.springframework.core.io.ByteArrayResource(qrBytes),
                    "image/png");
            } else {
                helper.setText(buildBookingHtml(booking, null), true);
            }

            mailSender.send(message);
            log.info("✉️ Booking confirmation sent to: {}", booking.getUser().getEmail());
        } catch (Exception e) {
            log.error("❌ Failed to send booking confirmation to {}: {}", booking.getUser().getEmail(), e.getMessage());
        }
    }

