    // ─────────────────────────────────────────────────────────────────
    //  9. PER-ATTENDEE INDIVIDUAL TICKET EMAIL (with unique QR)
    // ─────────────────────────────────────────────────────────────────
    @Async
    public void sendAttendeeTickets(com.eventbooking.model.Booking booking) {
        if (booking.getAttendees() == null || booking.getAttendees().isEmpty()) return;
        booking.getAttendees().forEach(attendee -> {
            try {
                MimeMessage message = mailSender.createMimeMessage();
                MimeMessageHelper helper = new MimeMessageHelper(message, true, "UTF-8");
                helper.setFrom(FROM);
                helper.setTo(attendee.getEmail());
                helper.setSubject("\ud83c\udf9f\ufe0f Your Ticket — " + booking.getEvent().getEventName());

                String cid = "qr_" + attendee.getQrToken();
                helper.setText(buildAttendeeTicketHtml(booking, attendee, cid), true);

                if (attendee.getQrCodeData() != null && attendee.getQrCodeData().contains("base64,")) {
                    String b64 = attendee.getQrCodeData().split(",")[1];
                    byte[] qrBytes = Base64.getDecoder().decode(b64);
                    helper.addInline(cid,
                        new org.springframework.core.io.ByteArrayResource(qrBytes),
                        "image/png");
                }
                mailSender.send(message);
                log.info("✉️ Attendee ticket sent to: {} for event: {}",
                    attendee.getEmail(), booking.getEvent().getEventName());
            } catch (Exception e) {
                log.error("❌ Attendee ticket email failed for {}: {}", attendee.getEmail(), e.getMessage());
            }
        });
    }

