    private String buildCancellationHtml(Event event, Booking booking) {
        return header("\ud83d\udeab Event Cancelled", event.getEventName() + " has been cancelled") + "<p style=\'color:#cbd5e1;\'>Hi <strong style=\'color:white;\'>" + booking.getUser().getName() + "</strong>,</p>" + "<p style=\'color:#94a3b8;\'>We regret to inform you that the following event has been <strong style=\'color:#f87171;\'>cancelled</strong>.</p>" + "<div style=\'background:rgba(239,68,68,0.1);border:1px solid rgba(239,68,68,0.3);border-radius:12px;padding:20px;margin:20px 0;\'>" + "<div class=\'row\'><span class=\'label\'>Event</span><span class=\'value\' style=\'color:#f87171;\'>" + event.getEventName() + "</span></div>" + "<div class=\'row\'><span class=\'label\'>Your Booking Ref</span><span class=\'value\'>" + booking.getBookingReference() + "</span></div>" + "<div class=\'row\'><span class=\'label\'>Tickets Booked</span><span class=\'value\'>" + booking.getNumberOfTickets() + "</span></div>" + "<div class=\'row\' style=\'border:none;\'><span class=\'label\'>Amount</span><span class=\'value\'>₹" + booking.getTotalAmount() + "</span></div>" + "</div>" + "<div style=\'background:rgba(34,197,94,0.1);border:1px solid rgba(34,197,94,0.3);border-radius:12px;padding:16px;margin:16px 0;text-align:center;\'>" + "<p style=\'color:#4ade80;font-weight:700;margin:0 0 4px;\'>\ud83d\udcb0 Refund Information</p>" + "<p style=\'color:#94a3b8;margin:0;font-size:14px;\'>Your booking has been cancelled. Please contact the admin for refund processing.</p>" + "</div>" + "<p style=\'color:#94a3b8;font-size:13px;\'>We apologize for the inconvenience. Please browse other available events.</p>" + "<div style=\'text-align:center;\'><a href=\'http://localhost:5173/events\' class=\'btn\'>\ud83c\udfad Browse Other Events</a></div>" + footer();
    }

    private String buildAnnouncementHtml(User user, String subject, String messageBody) {
        return header("\ud83d\udce3 " + subject, "Announcement from VelTech EventSphere") + "<p style=\'color:#cbd5e1;\'>Hi <strong style=\'color:white;\'>" + user.getName() + "</strong>,</p>" + "<div style=\'background:#0f1729;border-radius:12px;padding:24px;margin:20px 0;border:1px solid #2d3a5e;\'>" + "<p style=\'color:#e2e8f0;font-size:15px;line-height:1.7;margin:0;\'>" + messageBody.replace("\n", "<br>") + "</p>" + "</div>" + "<div style=\'text-align:center;\'><a href=\'http://localhost:5173/events\' class=\'btn\'>\ud83c\udfad Browse Events</a></div>" + footer();
    }

    private String buildRestrictionText(Event event) {
        boolean hasDepts = event.getTargetDepartments() != null && !event.getTargetDepartments().isEmpty();
        boolean hasYears = event.getTargetYears() != null && !event.getTargetYears().isEmpty();
        if (!hasDepts && !hasYears) return null;
        StringBuilder sb = new StringBuilder();
        if (hasDepts) {
            sb.append(String.join(", ", event.getTargetDepartments()));
        }
        if (hasYears) {
            if (hasDepts) sb.append(" · ");
            sb.append(event.getTargetYears().stream().map(y -> y + getOrdinal(y) + " Year").reduce((a, b) -> a + ", " + b).orElse(""));
        }
        return sb.toString();
    }

    private String getOrdinal(int n) {
        return switch (n) {
            case 1 -> "st";
            case 2 -> "nd";
            case 3 -> "rd";
            default -> "th";
        };
    }

    // ─────────────────────────────────────────────────────────────────
    //  LOGO (loaded once at startup from classpath)
    // ─────────────────────────────────────────────────────────────────
    private String logoBase64 = "";

    private void loadLogo() {
        try {
            var is = getClass().getResourceAsStream("/veltech-logo.png");
            if (is != null) {
                byte[] bytes = is.readAllBytes();
                logoBase64 = "data:image/png;base64," + java.util.Base64.getEncoder().encodeToString(bytes);
                log.info("✅ VelTech logo loaded ({} bytes)", bytes.length);
            } else {
                log.warn("⚠️ veltech-logo.png not found on classpath");
            }
        } catch (Exception e) {
            log.warn("⚠️ Failed to load logo: {}", e.getMessage());
        }
    }

    // ─────────────────────────────────────────────────────────────────
    //  10. CERTIFICATE EMAIL
    // ─────────────────────────────────────────────────────────────────
    @Async
    public void sendCertificateEmail(com.eventbooking.model.Attendee attendee,
                                     com.eventbooking.model.Event event,
                                     com.eventbooking.model.Booking booking) {
        try {
            MimeMessage message = mailSender.createMimeMessage();
            MimeMessageHelper helper = new MimeMessageHelper(message, true, "UTF-8");
            helper.setFrom(FROM);
            helper.setTo(attendee.getEmail());
            helper.setSubject("🎓 Certificate of Participation — " + event.getEventName());
            helper.setText(buildCertificateHtml(attendee, event, booking), true);
            mailSender.send(message);
            log.info("🎓 Certificate sent to: {}", attendee.getEmail());
        } catch (Exception e) {
            log.error("❌ Certificate email failed for {}: {}", attendee.getEmail(), e.getMessage());
        }
    }

